data.content:
Here's a solid MSTest approach using `HttpMessageHandler` fakes and proper cancellation/timeout patterns:

```csharp
[TestClass]
public class DataFetcherTests
{
    private static HttpClient CreateClient(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
    {
        return new HttpClient(new FakeHandler(handler));
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        using var client = CreateClient((_, _) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.OK)
            {
                Content = new StringContent("hello")
            }));

        var fetcher = new DataFetcher(client);
        var result = await fetcher.FetchAsync("http://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsHttpRequestException_OnFailure()
    {
        using var client = CreateClient((_, _) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.InternalServerError)));

        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("http://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_HonoursCancellation()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        using var client = CreateClient((_, ct) =>
        {
            ct.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage());
        });

        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("http://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_TimesOut_WithCancellationToken()
    {
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        using var client = CreateClient(async (_, ct) =>
        {
            await Task.Delay(TimeSpan.FromSeconds(10), ct); // simulate slow server
            return new HttpResponseMessage();
        });

        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("http://example.com", cts.Token));
    }

    // Minimal fake handler
    private sealed class FakeHandler(
        Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> func)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => func(request, cancellationToken);
    }
}
```

**Key patterns:**

| Scenario | Technique |
|----------|-----------|
| Cancellation | Pre-cancel a `CancellationTokenSource`, assert `TaskCanceledException` |
| Timeout | Use `new CancellationTokenSource(TimeSpan)` with a short deadline and a handler that delays longer |
| Fake HTTP | Custom `HttpMessageHandler` — no mocking library needed |
| MSTest timeout guard | Add `[Timeout(5000)]` at class or method level to fail-safe hung tests |

Add `[Timeout(5000)]` to the class if you want MSTest to kill any test that accidentally hangs:

```csharp
[TestClass]
[Timeout(5000)]
public class DataFetcherTests { ... }
```
